    69→    duration: theme.transitions.duration.leavingScreen,
    70→  }),
    71→  overflowX: 'hidden',
    72→  width: `calc(${theme.spacing(7)} + 1px)`,
    73→  [theme.breakpoints.up('sm')]: {
    74→    width: `calc(${theme.spacing(8)} + 1px)`,
    75→  },
    76→});
