    79→  width: drawerWidth,
    80→  flexShrink: 0,
    81→  whiteSpace: 'nowrap',
    82→  boxSizing: 'border-box',
    83→  variants: [
    84→    {
    85→      props: { open: true },
    86→      style: {
    87→        ...openedMixin(theme),
    88→        '.MuiDrawer-paper': openedMixin(theme),
    89→      },
    90→    },
    91→    {
    92→      props: { open: false },
    93→      style: {
    94→        ...closedMixin(theme),
    95→        '.MuiDrawer-paper': closedMixin(theme),
    96→      },
    97→    },
    98→  ],
    99→}));
