   101→type MenuItemDataType = {
   102→  name: string;
   103→  link?: string;
   104→  isSelected?: boolean;
   105→  icon: ReactElement;
   106→  isDivider?: boolean;
   107→};
   108→
   109→function LayoutInner({
   110→  children,
   111→  currentUser,
   112→  currentTeam,
   113→}: {
   114→  children: ReactNode;
   115→  currentUser: User;
   116→  currentTeam: Team;
   117→}) {
   118→  const { router, services } = useServicesHook();
   119→
   120→  const theme = useTheme();
   121→  const isSmallScreen = useMediaQuery(theme.breakpoints.down('md'));
   122→  const scrollTrigger = useScrollTrigger();
   123→
   124→  const [open, setOpen] = useState(!isSmallScreen);
   125→  const flipOpen = () => setOpen(!open);
   126→
   127→  const adminItem = {
   128→    name: translate(PAGE_INFO.ADMIN.name as keyof typeof translate),
   129→    icon: <AdminPanelSettingsOutlined />,
   130→    isSelected: router.pathname == PAGE_INFO.ADMIN.href(currentTeam.id),
   131→    link: PAGE_INFO.ADMIN.href(currentTeam.id),
   132→  };
   133→
   134→  const allResourceListItem = {
   135→    name: translate(
   136→      PAGE_INFO.MULTI_TEAMS_RESOURCES.name as keyof typeof translate,
   137→    ),
   138→    icon: <AdminPanelSettings />,
   139→    isSelected: router.pathname == PAGE_INFO.MULTI_TEAMS_RESOURCES.href(),
   140→    link: PAGE_INFO.MULTI_TEAMS_RESOURCES.href(),
   141→  };
   142→
   143→  const superAdminItems = [
   144→    {
   145→      name: translate(
   146→        PAGE_INFO.SUPER_ADMIN_TEAMS.name as keyof typeof translate,
   147→      ),
   148→      icon: <AdminPanelSettings />,
   149→      isSelected: router.pathname == PAGE_INFO.SUPER_ADMIN_TEAMS.href(),
   150→      link: PAGE_INFO.SUPER_ADMIN_TEAMS.href(),
   151→    },
   152→    {
   153→      name: translate(
   154→        PAGE_INFO.SUPER_ADMIN_NOTIFICATIONS.name as keyof typeof translate,
   155→      ),
   156→      icon: <AdminPanelSettings />,
   157→      isSelected: router.pathname == PAGE_INFO.SUPER_ADMIN_NOTIFICATIONS.href(),
   158→      link: PAGE_INFO.SUPER_ADMIN_NOTIFICATIONS.href(),
   159→    },
   160→    {
   161→      name: translate(
   162→        PAGE_INFO.SUPER_ADMIN_AI_COACH.name as keyof typeof translate,
   163→      ),
   164→      icon: <AdminPanelSettings />,
   165→      isSelected: router.pathname == PAGE_INFO.SUPER_ADMIN_AI_COACH.href(),
   166→      link: PAGE_INFO.SUPER_ADMIN_AI_COACH.href(),
   167→    },
   168→  ];
   169→
   170→  const menuItems: MenuItemDataType[] = [
   171→    {
   172→      name: translate(PAGE_INFO.SESSIONS.name as keyof typeof translate),
   173→      icon: <FormatListBulleted />,
   174→      isSelected: router.pathname == PAGE_INFO.SESSIONS.href(currentTeam.id),
   175→      link: PAGE_INFO.SESSIONS.href(currentTeam.id),
   176→    },
   177→    {
   178→      name: translate(PAGE_INFO.PLAYERS.name as keyof typeof translate),
   179→      icon: <Groups3Outlined />,
   180→      isSelected: router.pathname == PAGE_INFO.PLAYERS.href(currentTeam.id),
   181→      link: PAGE_INFO.PLAYERS.href(currentTeam.id),
   182→    },
   183→    ...(User.isAccessible(
   184→      currentUser,
   185→      currentTeam.id,
   186→      'management',
   187→      'read',
   188→      true,
   189→    )
   190→      ? [adminItem]
   191→      : []),
   192→    {
   193→      name: '_divider_0',
   194→      icon: <></>,
   195→      isDivider: true,
   196→    },
   197→    {
   198→      name: translate(PAGE_INFO.NOTIFICATIONS.name as keyof typeof translate),
   199→      icon: <NotificationsOutlined />,
   200→      isSelected: router.pathname == PAGE_INFO.NOTIFICATIONS.href(),
   201→      link: PAGE_INFO.NOTIFICATIONS.href(),
   202→    },
   203→    ...(User.isAccessible(currentUser, 'all', 'management', 'read', false)
   204→      ? [
   205→          // This will be changed when new role-region is created.
   206→          {
   207→            name: '_divider_1',
   208→            icon: <></>,
   209→            isDivider: true,
   210→          },
   211→          allResourceListItem,
   212→        ]
   213→      : []),
   214→    ...(User.isAccessible(currentUser, 'all', 'management', 'read', false)
   215→      ? [
   216→          {
   217→            name: '_divider_2',
   218→            icon: <></>,
   219→            isDivider: true,
   220→          },
   221→          ...superAdminItems,
   222→        ]
   223→      : []),
   224→  ];
   225→
   226→  const closeDrawerOnSmallScreen = () => {
   227→    if (isSmallScreen) {
   228→      setOpen(false);
   229→    }
   230→  };
   231→
   232→  // プランステータスの判定
   233→  const getPlanStatus = (): { status: PlanStatus | null } => {
   234→    // Production環境では表示しない
   235→    if (
   236→      EnvManager.config.APP_ENV === 'production' ||
   237→      currentTeam.teamType === TeamType.MULTIPLE
   238→    ) {
   239→      return { status: null };
   240→    }
   241→
   242→    // 期限内のAppleサブスクリプションがある場合は表示しない
   243→    if (
   244→      currentTeam.teamPlan?.endDate &&
   245→      currentTeam.teamPlan.endDate > new Date() &&
   246→      currentTeam.teamPlan.subscriptionType === 'apple'
   247→    ) {
   248→      return { status: null };
   249→    }
   250→
   251→    // 支払い失敗の場合
   252→    if (
   253→      currentTeam.billingFailureReason !== null &&
   254→      currentTeam.billingFailureReason !== ''
   255→    ) {
   256→      return { status: 'billing_failure' };
   257→    }
   258→
   259→    // teamPlan が無料プランの場合
   260→    if (!currentTeam.teamPlan?.plan.isPaid) {
   261→      return { status: 'upgrade_prompt' };
   262→    }
   263→
   264→    // プランが利用不可の場合（期限切れや利用制限に達している場合）
   265→    if (!currentTeam.teamPlanAvailability.isAvailable) {
   266→      const reason = currentTeam.teamPlanAvailability.unavailableReason;
   267→      if (reason === 'team_plan_expired' || reason === 'no_team_plan_found') {
   268→        return { status: 'upgrade_prompt' };
   269→      }
   270→    }
   271→
   272→    // 既存のplanがisTopTierPlanの場合は表示しない
   273→    if (isTopTierPlan(currentTeam.teamPlan?.plan.id)) {
   274→      return { status: null };
   275→    }
   276→
   277→    // 利用制限に達している場合
   278→    if (currentTeam.ballRate >= 1) {
   279→      return { status: 'limit_reached' };
   280→    }
   281→
   282→    // 利用制限が近づいている場合
   283→    const isUsageLimitApproaching = currentTeam.ballRate >= 0.9;
   284→    if (isUsageLimitApproaching) {
   285→      return { status: 'pre_warning' };
   286→    }
   287→
   288→    // その他の場合は常にUpgrade promptを表示
   289→    return { status: 'upgrade_prompt' };
   290→  };
   291→
   292→  const planStatus = getPlanStatus();
   293→
   294→  const handleUpgrade = () => {
   295→    // 期限内のStripeサブスクリプションがある場合は請求ポータルを開く
   296→    if (currentTeam.teamPlan?.subscriptionType === 'stripe') {
   297→      handleBillingPortal(planStatus.status);
   298→      return;
   299→    }
   300→    // 期限内のTeamPlanがない場合はプラン選択ページに遷移
   301→    router.push('/account/plans');
   302→  };
   303→
   304→  const handleBillingPortal = async (status: PlanStatus | null) => {
   305→    try {
   306→      let type:
   307→        | 'subscription_update'
   308→        | 'subscription_cancel'
   309→        | 'payment_method_update'
   310→        | undefined;
   311→      if (status === 'billing_failure') {
   312→        type = 'payment_method_update';
   313→      } else if (
   314→        status === 'upgrade_prompt' ||
   315→        status === 'pre_warning' ||
   316→        status === 'limit_reached'
   317→      ) {
   318→        type = 'subscription_update';
   319→      }
   320→
   321→      const result = await services.default.payment.createBillingPortalSession({
   322→        teamId: currentTeam.id,
   323→        type,
   324→      });
   325→      if (result.error) {
   326→        throw result.error;
   327→      }
   328→      if (result.data?.url) {
   329→        window.open(result.data.url, '_blank', 'noopener,noreferrer');
   330→      }
   331→    } catch (error) {
   332→      enqueueSnackbar({
   333→        variant: 'error',
   334→        message: translate('payment_error_occurred'),
   335→      });
   336→    }
   337→  };
   338→
   339→  return (
   340→    <>
   341→      <Box sx={{ display: { xs: 'block', md: 'none' } }}>
   342→        <Slide appear={false} direction="down" in={!scrollTrigger}>
   343→          <AppBar variant="outlined" color="inherit" elevation={0}>
   344→            <Toolbar sx={{ display: 'flex', justifyContent: 'space-between' }}>
   345→              <Box sx={{ display: 'flex', flex: 1 }}>
   346→                <IconButton
   347→                  size="large"
   348→                  edge="start"
   349→                  color="inherit"
   350→                  aria-label="menu"
   351→                  sx={{ mr: 2 }}
   352→                  onClick={flipOpen}
   353→                >
   354→                  <MenuIcon />
   355→                </IconButton>
   356→              </Box>
   357→              <Box sx={{ display: 'flex', flex: 1, justifyContent: 'center' }}>
   358→                <Image
   359→                  src={AppConstants.LOGO_URL}
   360→                  alt=""
   361→                  priority={true}
   362→                  height="40"
   363→                  width="150"
   364→                />
   365→              </Box>
   366→              <Box sx={{ display: 'flex', flex: 1 }} />
   367→            </Toolbar>
   368→          </AppBar>
   369→        </Slide>
   370→        <Toolbar />
   371→      </Box>
   372→      <Box sx={{ display: 'flex' }}>
   373→        <Drawer
   374→          open={open}
   375→          onClose={flipOpen}
   376→          variant={isSmallScreen ? 'temporary' : 'permanent'}
   377→          slotProps={{
   378→            root: {
   379→              keepMounted: true, // Better open performance on mobile.
   380→            },
   381→          }}
   382→        >
   383→          <List sx={{ flex: 1 }}>
   384→            <ListItem disablePadding>
   385→              <ListItemButton
   386→                onClick={flipOpen}
   387→                sx={{
   388→                  justifyContent: 'space-between',
   389→                }}
   390→              >
   391→                <Image
   392→                  src={AppConstants.LOGO_URL}
   393→                  alt=""
   394→                  priority={true}
   395→                  height="40"
   396→                  width="150"
   397→                  style={{ display: open ? 'block' : 'none' }}
   398→                />
   399→                <ListItemIcon
   400→                  sx={{
   401→                    minWidth: 0,
   402→                    mr: open ? 1 : 'auto',
   403→                    justifyContent: 'center',
   404→                  }}
   405→                >
   406→                  {open ? (
   407→                    <KeyboardDoubleArrowLeft />
   408→                  ) : (
   409→                    <KeyboardDoubleArrowRight />
   410→                  )}
   411→                </ListItemIcon>
   412→              </ListItemButton>
   413→            </ListItem>
   414→            <Divider sx={{ mt: 2, mb: 6 }} />
   415→            <ListItem sx={{ opacity: open ? 1 : 0, mb: 2, py: 0 }}>
   416→              <Typography>{translate('navigation')}</Typography>
   417→            </ListItem>
   418→            {menuItems.map((x) => {
   419→              return (
   420→                <React.Fragment key={x.name}>
   421→                  {x.link ? (
   422→                    <ListItem disablePadding>
   423→                      <Link
   424→                        href={x.link}
   425→                        passHref
   426→                        style={{ width: '100%', textDecoration: 'none' }}
   427→                        onClick={closeDrawerOnSmallScreen}
   428→                      >
   429→                        <ListItemButton
   430→                          selected={!!x.isSelected}
   431→                          sx={{
   432→                            justifyContent: 'center',
   433→                          }}
   434→                        >
   435→                          <ListItemIcon
   436→                            sx={{
   437→                              minWidth: 0,
   438→                              mr: open ? 3 : 'auto',
   439→                              justifyContent: 'center',
   440→                            }}
   441→                          >
   442→                            {x.icon}
   443→                          </ListItemIcon>
   444→                          <ListItemText
   445→                            primary={x.name}
   446→                            sx={{
   447→                              opacity: open ? 1 : 0,
   448→                            }}
   449→                          />
   450→                        </ListItemButton>
   451→                      </Link>
   452→                    </ListItem>
   453→                  ) : x.isDivider ? (
   454→                    <Divider sx={{ my: 1 }} />
   455→                  ) : (
   456→                    <></>
   457→                  )}
   458→                </React.Fragment>
   459→              );
   460→            })}
   461→          </List>
   462→
   463→          {/* Plan Status Card */}
   464→          {planStatus.status !== null && (
   465→            <PlanStatusCard
   466→              status={planStatus.status}
   467→              open={open}
   468→              onUpgrade={handleUpgrade}
   469→            />
   470→          )}
   471→
   472→          {/* TODO: remove this */}
   473→          {EnvManager.config.APP_ENV != 'production' && (
   474→            <Box
   475→              className={'develop'}
   476→              sx={{ padding: 0.5, background: 'lightgray' }}
   477→            >
   478→              build: {EnvManager.config.APP_UPDATED_AT}
   479→              <br />
   480→              commit: {EnvManager.config.GIT_COMMIT_HASH}
   481→              <br />
   482→            </Box>
   483→          )}
   484→
   485→          <Box>
   486→            <Divider></Divider>
   487→            <Link
   488→              href={PAGE_INFO.ACCOUNT.href()}
   489→              passHref
   490→              style={{ width: '100%', textDecoration: 'none' }}
   491→              onClick={closeDrawerOnSmallScreen}
   492→            >
   493→              <ListItemButton
   494→                selected={
   495→                  router.pathname == PAGE_INFO.ACCOUNT.href() ||
   496→                  router.pathname == PAGE_INFO.ACCOUNT_EDIT.href()
   497→                }
   498→                sx={{
   499→                  justifyContent: 'center',
   500→                }}
   501→              >
   502→                <ListItemIcon
   503→                  sx={{
   504→                    minWidth: 0,
   505→                    mr: open ? 3 : 'auto',
   506→                    justifyContent: 'center',
   507→                  }}
   508→                >
   509→                  <ImageOrAvatar
   510→                    url={currentUser.profile?.presignedImageUrl}
   511→                    width={40}
   512→                    height={40}
   513→                  />
   514→                </ListItemIcon>
   515→                <ListItemText
   516→                  primary={currentUser?.profile?.username ?? '-'}
   517→                  sx={{
   518→                    opacity: open ? 1 : 0,
   519→                  }}
   520→                />
   521→              </ListItemButton>
   522→            </Link>
   523→          </Box>
   524→        </Drawer>
   525→        <Box
   526→          component="main"
   527→          sx={{
   528→            flexGrow: 1,
   529→            py: 2,
   530→            px: 2,
   531→            overflowX: 'auto',
   532→            minHeight: '100vh',
   533→            background: '#F9F9F9',
   534→          }}
   535→        >
   536→          {children}
   537→        </Box>
   538→      </Box>
   539→    </>
   540→  );
   541→}
   542→
   543→export default function ConsoleLayout({ children }: { children: ReactNode }) {
   544→  const { services, router } = useServicesHook();
   545→  const [_, setIsSubmitting] = useState<boolean>(false);
   546→  const currentUser = useSelector((state) => state.user.me);
   547→  const currentTeam = useSelector((state) => state.user.currentTeam);
   548→  const userError = useSelector((state) => state.user.error);
   549→  const loginStatus = useSelector((state) => state.user.loginStatus);
   550→
   551→  const logout = () => {
   552→    wrapForLoading(setIsSubmitting, async () => {
   553→      await services.default.auth.signOut();
   554→      location.href = PAGE_INFO.SIGN_IN.href();
   555→    });
   556→  };
   557→
   558→  useEffect(() => {
   559→    if (loginStatus === 'initial') {
   560→      return;
   561→    }
   562→
   563→    if (loginStatus != 'yes') {
   564→      logger.debug('SD: no user - redirect to signin');
   565→      const callbackUrl = encodeURIComponent(window.location.pathname + window.location.search);
   566→      router.replace(`${PAGE_INFO.SIGN_IN.href()}?callbackUrl=${callbackUrl}`);
   567→    }
   568→  }, [loginStatus]);
   569→
   570→  if (loginStatus == 'error' && userError) {
   571→    return (
   572→      <>
   573→        <CriticalError error={userError} />
   574→      </>
   575→    );
   576→  }
   577→
   578→  return currentUser && currentTeam ? (
   579→    <LayoutInner currentUser={currentUser} currentTeam={currentTeam}>
   580→      {children}
   581→    </LayoutInner>
   582→  ) : currentUser ? (
   583→    <Box
   584→      sx={{
   585→        p: 2,
   586→      }}
   587→    >
   588→      <Typography>{translate('no_active_teams_found')}</Typography>
   589→      <Button color="error" sx={{ mt: 2 }} variant="contained" onClick={logout}>
   590→        {translate('sign_out')}
   591→      </Button>
   592→    </Box>
   593→  ) : (
   594→    <>
   595→      {
   596→        // nothing to do (waiting initialization)
   597→      }
   598→    </>
   599→  );
   600→}
