**改善案**:
```typescript
// 1. UseCase 層の導入
// src/usecases/auth/SignInUseCase.ts
export class SignInUseCase {
  constructor(
    private authRepository: IAuthRepository,
    private userRepository: IUserRepository
  ) {}

  async execute(email: string, password: string): Promise<SignInResult> {
    const { user, session } = await this.authRepository.signIn(email, password);
    const userData = await this.userRepository.getById(user.id);
    return { user: userData, session };
  }
