  // サイドバーロジック
});

const MemoizedAppBar = React.memo(({ onMenuOpen, user }: AppBarProps) => {
  // AppBarロジック
});

// 2. Redux selector最適化
const selectUser = createSelector(
  (state: AppState) => state.auth.user,
  (user) => user
);

const ConsoleLayout: FC<ConsoleLayoutProps> = ({ children }) => {
  const user = useSelector(selectUser, shallowEqual);

  return (
    <>
      <MemoizedAppBar onMenuOpen={handleMenuOpen} user={user} />
