      <Box component="main">{children}</Box>
    </>
  );
};
```

### 5. ビジネスロジックの漏出 (signin.tsx:48-67)

**問題**: Presentation 層に API 通信とビジネスロジックが直接実装されています。

**修正案**:
```typescript
// hooks/useSignIn.ts
export const useSignIn = () => {
  const router = useRouter();
  const { services } = useServicesHook();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<ServiceError | null>(null);

  const signIn = async (email: string, password: string) => {
    setIsSubmitting(true);
    setError(null);

    try {
      const result = await services.default.auth.signin(email, password);
      if (result.error) {
        setError(result.error);
        return;
      }

      const callbackUrl = router.query.callbackUrl as string | undefined;
      location.href = callbackUrl ? decodeURIComponent(callbackUrl) : PAGE_INFO.TOP.href();
    } finally {
      setIsSubmitting(false);
    }
  };

  return { signIn, isSubmitting, error };
};

// signin.tsx
const { signIn, isSubmitting, error } = useSignIn();
```

