import { validateRedirectUrl, createSafeCallbackUrl } from '../redirect-validator';

// PAGE_INFO.TOP.href() をモック
jest.mock('@/constants/page.constants', () => ({
  PAGE_INFO: {
    TOP: {
      href: () => '/',
    },
  },
}));

// logger をモック
jest.mock('@/utils/logger', () => ({
  logger: {
    warn: jest.fn(),
    error: jest.fn(),
  },
}));

describe('validateRedirectUrl', () => {
  describe('安全な URL（許可されるべき）', () => {
    it('相対パス: ルートパス', () => {
      expect(validateRedirectUrl('/')).toBe('/');
    });

    it('相対パス: サブディレクトリ', () => {
      expect(validateRedirectUrl('/dashboard')).toBe('/dashboard');
    });

    it('相対パス: クエリパラメータ付き', () => {
      expect(validateRedirectUrl('/sessions?tab=active')).toBe(
        '/sessions?tab=active',
      );
    });

    it('相対パス: ハッシュ付き', () => {
      expect(validateRedirectUrl('/profile#settings')).toBe(
        '/profile#settings',
      );
    });

    it('相対パス: クエリパラメータとハッシュ両方', () => {
      expect(validateRedirectUrl('/page?id=123#section')).toBe(
        '/page?id=123#section',
      );
    });

    it('相対パス: 深い階層', () => {
      expect(validateRedirectUrl('/admin/users/edit/123')).toBe(
        '/admin/users/edit/123',
      );
    });
  });

  describe('危険な URL（拒否されるべき）', () => {
    it('絶対 URL: https プロトコル', () => {
      expect(validateRedirectUrl('https://evil.com')).toBe('/');
    });

    it('絶対 URL: http プロトコル', () => {
      expect(validateRedirectUrl('http://evil.com')).toBe('/');
    });

    it('絶対 URL: プロトコル相対（//）', () => {
      expect(validateRedirectUrl('//evil.com')).toBe('/');
    });

    it('絶対 URL: プロトコル相対でパス付き', () => {
      expect(validateRedirectUrl('//evil.com/phishing')).toBe('/');
    });

    it('JavaScript スキーム', () => {
      expect(validateRedirectUrl('javascript:alert(1)')).toBe('/');
    });

    it('Data URL スキーム', () => {
      expect(validateRedirectUrl('data:text/html,<script>alert(1)</script>')).toBe('/');
    });

    it('VBScript スキーム', () => {
      expect(validateRedirectUrl('vbscript:msgbox(1)')).toBe('/');
    });

    it('File スキーム', () => {
      expect(validateRedirectUrl('file:///etc/passwd')).toBe('/');
    });

    it('パストラバーサル: Unix スタイル', () => {
      expect(validateRedirectUrl('/../../../etc/passwd')).toBe('/');
    });

    it('パストラバーサル: Windows スタイル', () => {
      expect(validateRedirectUrl('/..\\..\\windows\\system32')).toBe('/');
    });

    it('パストラバーサル: パス途中', () => {
      expect(validateRedirectUrl('/normal/../../../etc/passwd')).toBe('/');
    });

    it('空文字列', () => {
      expect(validateRedirectUrl('')).toBe('/');
    });

    it('null', () => {
      expect(validateRedirectUrl(null)).toBe('/');
    });

    it('undefined', () => {
      expect(validateRedirectUrl(undefined)).toBe('/');
    });

    it('空白文字のみ', () => {
      expect(validateRedirectUrl('   ')).toBe('/');
    });

    it('相対パスではない: バックスラッシュ始まり', () => {
      expect(validateRedirectUrl('\\evil.com')).toBe('/');
    });
  });

  describe('エッジケース', () => {
    it('URL エンコードされた絶対 URL', () => {
      // %68%74%74%70 = "http"
      expect(validateRedirectUrl('%68%74%74%70://evil.com')).toBe('/');
    });

    it('大文字小文字混在のプロトコル: HTTPS', () => {
      expect(validateRedirectUrl('HtTpS://evil.com')).toBe('/');
    });

    it('大文字小文字混在のプロトコル: JavaScript', () => {
      expect(validateRedirectUrl('JaVaScRiPt:alert(1)')).toBe('/');
    });

    it('大文字小文字混在のプロトコル: Data', () => {
      expect(validateRedirectUrl('DaTa:text/html,<script>alert(1)</script>')).toBe('/');
    });

    it('スペースを含む URL', () => {
      expect(validateRedirectUrl('/path with spaces')).toBe(
        '/path%20with%20spaces',
      );
    });

    it('日本語を含む URL', () => {
      const result = validateRedirectUrl('/ユーザー/設定');
      expect(result).toContain('%E3%83%A6%E3%83%BC%E3%82%B6%E3%83%BC');
    });

    it('特殊文字を含む URL', () => {
      expect(validateRedirectUrl('/page?q=a&b=c')).toBe('/page?q=a&b=c');
    });
  });
});

describe('createSafeCallbackUrl', () => {
  beforeEach(() => {
    // window.location をモック
    delete (global as any).window;
    (global as any).window = {
      location: {
        pathname: '/sessions',
        search: '?status=active',
      },
    };
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  it('現在のパスとクエリパラメータをエンコードして返す', () => {
    const result = createSafeCallbackUrl();
    expect(result).toBe(encodeURIComponent('/sessions?status=active'));
  });

  it('クエリパラメータなしのパス', () => {
    (global as any).window.location.search = '';
    const result = createSafeCallbackUrl();
    expect(result).toBe(encodeURIComponent('/sessions'));
  });

  it('パストラバーサルを含む場合はデフォルトを返す', () => {
    (global as any).window.location.pathname = '/../etc/passwd';
    (global as any).window.location.search = '';
    const result = createSafeCallbackUrl();
    expect(result).toBe(encodeURIComponent('/'));
  });

  it('window が未定義の場合（SSR）はデフォルトを返す', () => {
    delete (global as any).window;
    const result = createSafeCallbackUrl();
    expect(result).toBe(encodeURIComponent('/'));
  });
});

