const createJestConfig = nextJest({
  // Next.js アプリのパスを指定
  dir: './',
});

// Jest のカスタム設定
const config: Config = {
  // テスト環境を jsdom に設定（React コンポーネントのテスト用）
  testEnvironment: 'jsdom',

  // セットアップファイルを指定
  setupFilesAfterEnv: ['<rootDir>/jest.setup.ts'],

  // モジュール名のマッピング（パスエイリアス）
  moduleNameMapper: {
    // @/ を src/ にマッピング
    '^@/(.*)$': '<rootDir>/src/$1',

    // CSS モジュールのモック
    '^.+\\.module\\.(css|sass|scss)$': 'identity-obj-proxy',

    // CSS ファイルのモック
    '^.+\\.(css|sass|scss)$': '<rootDir>/__mocks__/styleMock.js',

    // 画像などの静的ファイルのモック
    '^.+\\.(jpg|jpeg|png|gif|webp|avif|svg)$': '<rootDir>/__mocks__/fileMock.js',
  },

  // テストファイルのパターン
  testMatch: [
    '**/__tests__/**/*.{js,jsx,ts,tsx}',
    '**/*.{spec,test}.{js,jsx,ts,tsx}',
  ],

  // カバレッジレポートの設定
  collectCoverageFrom: [
    'src/**/*.{js,jsx,ts,tsx}',
    '!src/**/*.d.ts',
    '!src/**/*.stories.{js,jsx,ts,tsx}',
    '!src/**/__tests__/**',
  ],

  // カバレッジレポートのディレクトリ
  coverageDirectory: 'coverage',

  // カバレッジレポートの形式
  coverageReporters: ['text', 'lcov', 'html'],

  // テスト時に無視するパス
  testPathIgnorePatterns: [
    '<rootDir>/node_modules/',
    '<rootDir>/.next/',
    '<rootDir>/out/',
    '<rootDir>/public/',
    '<rootDir>/playwright/',
  ],

  // トランスフォーム設定は next/jest が自動で設定
  // transform は明示的に指定しない（next/jest に任せる）

  // グローバル変数のモック
  globals: {
    'ts-jest': {
      tsconfig: {
        jsx: 'react-jsx',
      },
    },
  },
};

// Next.js の設定を含めた Jest 設定をエクスポート
export default createJestConfig(config);

// Jest のセットアップファイル
// テスト実行前に一度だけ実行される

// @testing-library/jest-dom のカスタムマッチャーを追加
// これにより toBeInTheDocument() などのマッチャーが使用可能になる
import '@testing-library/jest-dom';

// グローバルなモック設定
// 必要に応じてグローバルなモックをここに追加できます

// 例: console.error のモック（不要なエラーログを抑制）
// const originalError = console.error;
// beforeAll(() => {
//   console.error = jest.fn();
// });
// afterAll(() => {
//   console.error = originalError;
// });

// 例: window.matchMedia のモック（Material-UI などで必要な場合）
Object.defineProperty(window, 'matchMedia', {
  writable: true,
  value: jest.fn().mockImplementation((query) => ({
    matches: false,
    media: query,
    onchange: null,
    addListener: jest.fn(), // 非推奨
    removeListener: jest.fn(), // 非推奨
    addEventListener: jest.fn(),
    removeEventListener: jest.fn(),
    dispatchEvent: jest.fn(),
  })),
});

// 例: IntersectionObserver のモック
global.IntersectionObserver = class IntersectionObserver {
  constructor() {}
  disconnect() {}
  observe() {}
  takeRecords() {
    return [];
  }
  unobserve() {}
} as any;

// CSS ファイルのモック
// Jest でテストする際に CSS ファイルを空のオブジェクトとして扱う
module.exports = {};

// 画像などの静的ファイルのモック
// Jest でテストする際に画像ファイルを文字列として扱う
module.exports = 'test-file-stub';

